// Parse PatentsView API response and extract the 6 required fields per patent.
// Also filters out patents that have an assignee (i.e. already assigned to a company).
// Maps to: Patent Discovery stage.

const response = $input.first().json;
const patents = response.patents || [];

const results = [];

for (const patent of patents) {
  // Skip patents that have an assignee — we only want unassigned ones
  if (patent.assignee_id && patent.assignee_id !== null && patent.assignee_id !== '') {
    continue;
  }

  const inventors = patent.inventors || [];
  const attorneys = patent.attorneys || [];

  const primaryInventor = inventors[0] || {};
  const primaryAttorney = attorneys[0] || {};

  const inventorName = [
    primaryInventor.inventor_first_name || '',
    primaryInventor.inventor_last_name || ''
  ].filter(Boolean).join(' ').trim() || 'Unknown';

  const attorneyName = [
    primaryAttorney.attorney_first_name || '',
    primaryAttorney.attorney_last_name || ''
  ].filter(Boolean).join(' ').trim() || 'Unknown';

  const location = [
    primaryInventor.inventor_city || '',
    primaryInventor.inventor_state || ''
  ].filter(Boolean).join(', ') || 'Unknown';

  results.push({
    json: {
      patent_number:  patent.patent_id || '',
      patent_summary: patent.patent_title || '',
      filing_date:    patent.patent_date || '',
      inventor_name:  inventorName,
      inventor_first: primaryInventor.inventor_first_name || '',
      inventor_last:  primaryInventor.inventor_last_name || '',
      attorney_name:  attorneyName,
      attorney_first: primaryAttorney.attorney_first_name || '',
      attorney_last:  primaryAttorney.attorney_last_name || '',
      location:       location,
      // Enrichment fields — populated in later nodes
      inventor_email:    '',
      inventor_linkedin: '',
      confidence_score:  0,
      route:             'pending',
      sequence:          '',
      status:            'pending',
      notes:             ''
    }
  });
}

if (results.length === 0) {
  // Return a single item flagging no results so the workflow completes cleanly
  return [{ json: { no_results: true, message: 'No unassigned patents found this week.' } }];
}

return results;

// Score enrichment confidence for the inventor record.
// Combines signals from Apollo response with the original patent data.
// Low scores protect Instantly sender reputation by blocking unverified leads.

const apolloData  = $input.first().json;
const patentData  = $('Loop — One Patent at a Time').item.json;

const person = apolloData.person || {};
const email  = person.email || '';
const emailStatus = person.email_status || '';  // 'verified', 'likely', 'guessed', etc.
const linkedin    = person.linkedin_url || '';
const employment  = person.employment_history || [];
const numDataPoints = Object.keys(person).filter(k => person[k] !== null && person[k] !== '').length;

let score = 0;
let notes = [];

// +40 if any email found
if (email && email.includes('@')) {
  score += 40;
  notes.push('Email found');
} else {
  notes.push('No email found');
}

// +20 if email is verified by Apollo
if (emailStatus === 'verified') {
  score += 20;
  notes.push('Email verified');
} else if (email) {
  notes.push(`Email status: ${emailStatus}`);
}

// +20 if LinkedIn URL found
if (linkedin) {
  score += 20;
  notes.push('LinkedIn found');
} else {
  notes.push('No LinkedIn');
}

// +10 if Apollo record has more than 3 data points (richer profile)
if (numDataPoints > 3) {
  score += 10;
  notes.push('Rich Apollo profile');
}

// +10 if location matches patent filing location
const patentLocation = (patentData.location || '').toLowerCase();
const apolloCity     = (person.city || '').toLowerCase();
if (apolloCity && patentLocation.includes(apolloCity)) {
  score += 10;
  notes.push('Location matches');
}

// Determine routing based on score thresholds
let route;
if (score >= 70) {
  route = 'inventor_found';
} else if (score >= 40) {
  route = 'attorney_fallback';
} else {
  route = 'needs_review';
}

return [{
  json: {
    // Carry forward all original patent fields
    ...patentData,
    // Enrichment results
    inventor_email:    email,
    inventor_linkedin: linkedin,
    apollo_email_status: emailStatus,
    confidence_score:  score,
    route:             route,
    notes:             notes.join(' | '),
    // Raw Apollo person object for attorney fallback use
    apollo_person:     person
  }
}];

// Merge attorney Apollo enrichment back onto the original patent data.
// Applies same confidence check — if attorney email also missing, flag for review.

const apolloData = $input.first().json;
const patentData = $('Score Confidence').item.json;

const person = apolloData.person || {};
const email  = person.email || '';
const linkedin = person.linkedin_url || '';

let status, sequence, notes;

if (email && email.includes('@')) {
  status   = 'attorney_sequence';
  sequence = 'DEMO_ATTORNEY_CAMPAIGN_ID';
  notes    = `Attorney fallback — email found (${person.email_status || 'unknown status'})`;
} else {
  status   = '⚠️ Needs Manual Review';
  sequence = '';
  notes    = 'Attorney fallback — no email found either. Manual review required.';
}

return [{
  json: {
    ...patentData,
    attorney_email:    email,
    attorney_linkedin: linkedin,
    route:             'attorney_fallback',
    status:            status,
    sequence:          sequence,
    notes:             notes
  }
}];
